                "phone123!",
                "!!!@@@###",
                "     ",
                "\t\n"
        })
        void createUserShouldAcceptInvalidPhoneNumbersAsIs(String phoneNumber) {
            UserCreateRequest payload = new UserCreateRequest("Invalid User", "invaliduser+" + phoneNumber.hashCode() + "@example.com", "USER", phoneNumber);

